export function getCategoriesForLicensor(licensor: string): string[] {
  if (CATEGORIES[licensor]) return CATEGORIES[licensor]
  const key = Object.keys(CATEGORIES).find(
    k => k.toLowerCase().includes(licensor.toLowerCase()) || licensor.toLowerCase().includes(k.toLowerCase())
  )
  return key ? CATEGORIES[key] : []
}
